import{c as a,Q as t,j as o,m as r}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Introduction","description":"What MuHaven is, why agentic, and how the four surfaces fit together.","frontmatter":{"title":"Introduction","description":"What MuHaven is, why agentic, and how the four surfaces fit together."},"headers":[],"relativePath":"get-started/introduction.md","filePath":"get-started/introduction.md","lastUpdated":1778983454000}'),n={name:"get-started/introduction.md"};function s(i,e,h,l,d,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="welcome-to-muhaven" tabindex="-1">Welcome to MuHaven <a class="header-anchor" href="#welcome-to-muhaven" aria-label="Permalink to &quot;Welcome to MuHaven&quot;">​</a></h1><p>MuHaven is a <strong>confidential real-world-asset (RWA) portfolio</strong>. Your token balances are encrypted on-chain with Fully Homomorphic Encryption (<a href="https://docs.fhenix.io" target="_blank" rel="noreferrer">Fhenix CoFHE</a>). You hold them in a passkey-bound <strong>MuHaven wallet</strong> (a ZeroDev-powered smart account, EIP-4337). And — the part this documentation focuses on — you operate the whole thing through one of four <strong>agentic surfaces</strong> that all talk to the same underlying SDK and the same on-chain policy gate.</p><h2 id="what-agentic-means-in-muhaven" tabindex="-1">What &quot;agentic&quot; means in MuHaven <a class="header-anchor" href="#what-agentic-means-in-muhaven" aria-label="Permalink to &quot;What &quot;agentic&quot; means in MuHaven&quot;">​</a></h2><p>A regular LLM answers questions. An agent <strong>does things</strong>.</p><p>When you ask ChatGPT &quot;what&#39;s the best RWA yield?&quot;, it answers. When you tell HavenBot <em>&quot;buy $500 of <code>&lt;TOKEN&gt;</code> from a stablecoin position&quot;</em>, it:</p><ol><li>Reads current rates and the deviation-gated NAV.</li><li>Drafts an allocation and shows you the cleartext preview.</li><li>Waits for your passkey-confirmation (or a scoped session-key signature, depending on your tier).</li><li>Signs the UserOp and settles atomically through <code>MuHavenSubscription.purchase</code>.</li><li>Writes a row to your audit log.</li></ol><p>Encrypted balances never leave your local decrypt permit. The LLM never holds your key. The agent never bypasses the policy gate.</p><h2 id="the-four-surfaces" tabindex="-1">The four surfaces <a class="header-anchor" href="#the-four-surfaces" aria-label="Permalink to &quot;The four surfaces&quot;">​</a></h2><p>Each surface is a different way to reach the <strong>same</strong> SDK and the <strong>same</strong> policy gate. Pick whichever matches where you already are.</p><table tabindex="0"><thead><tr><th>Surface</th><th>Where you use it</th><th>Best for</th></tr></thead><tbody><tr><td><strong><a href="/havenbot/overview">HavenBot</a></strong></td><td>In the MuHaven dashboard at <code>muhaven.app/agent</code></td><td>Newcomers. Guided UX. Click-confirmable previews.</td></tr><tr><td><strong><a href="/mcp/overview"><code>@muhaven/mcp</code></a></strong></td><td>Claude Code, Claude Desktop, Cursor, or any MCP-aware host</td><td>Power users who already chat with their own LLM.</td></tr><tr><td><strong><a href="/openclaw/overview">OpenClaw + Telegram</a></strong></td><td>Telegram (mobile-first) + the OpenClaw skill runtime</td><td>Phone-first investors. Three confirmation tiers.</td></tr><tr><td><strong><a href="/checkout/overview">Hosted Checkout</a></strong></td><td>A pay-link an issuer shares (<code>muhaven.app/pay/...</code>)</td><td>One-off buyers. Pay with a passkey, no install.</td></tr></tbody></table><p>See <a href="/get-started/choosing-a-surface">Choosing a surface</a> for a decision tree.</p><h2 id="what-muhaven-is-and-isn-t" tabindex="-1">What MuHaven is (and isn&#39;t) <a class="header-anchor" href="#what-muhaven-is-and-isn-t" aria-label="Permalink to &quot;What MuHaven is (and isn&#39;t)&quot;">​</a></h2><p><strong>MuHaven is:</strong></p><ul><li>A confidential RWA portfolio with FHE-encrypted balances.</li><li>A passkey-bound smart account — no seed phrase, no MetaMask popup, no private key on your device.</li><li>A <em>tiered-autonomy</em> agent layer: you choose how much the agent can do without asking you each time.</li><li>An on-chain policy gate that rejects any tool-call outside your declared scope. The LLM <strong>proposes</strong>; the gate <strong>disposes</strong>.</li></ul><p><strong>MuHaven is not:</strong></p><ul><li>A financial advisor. Tools surface information; they don&#39;t recommend specific securities.</li><li>A custodial wallet. You sign with your passkey; MuHaven never holds your key.</li><li>A pure read-only dashboard. The four surfaces all support proposing and (with confirmation) executing real on-chain actions.</li></ul><h2 id="what-s-available" tabindex="-1">What&#39;s available <a class="header-anchor" href="#what-s-available" aria-label="Permalink to &quot;What&#39;s available&quot;">​</a></h2><p>The four surfaces are live on Arbitrum Sepolia (testnet) and rolling out on Arbitrum One (production):</p><ul><li>HavenBot at <code>muhaven.app/agent</code> — streaming chat, per-action ConfirmModal, 17 tools.</li><li><code>@muhaven/mcp</code> published on npm — install in any MCP host, 25 tools (8 read-only with the read-only flag).</li><li>OpenClaw skill <code>muhaven-rwa-skill</code> on ClawHub + Telegram bot live.</li><li>Hosted checkout at <code>muhaven.app/pay</code> — fragment-key URL scheme, AES-256-GCM payload, Stripe-pattern webhooks.</li><li>Tiered autonomy engine + audit log + <code>/pause</code> kill-switch.</li></ul><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><div class="mh-card-grid"><a class="mh-card" href="/get-started/quickstart"><h3>Quickstart</h3><p>From passkey to first encrypted buy.</p></a><a class="mh-card" href="/get-started/choosing-a-surface"><h3>Choosing a surface</h3><p>Decision tree: HavenBot vs MCP vs Telegram vs Checkout.</p></a><a class="mh-card" href="/get-started/privacy-boundary"><h3>Privacy boundary</h3><p>What the operator sees, what the LLM sees, what stays encrypted.</p></a><a class="mh-card" href="/policy/tiered-autonomy"><h3>Tiered autonomy</h3><p>How Advisory / Confirm / Policy-bound actually work.</p></a></div>',21)])])}const m=a(n,[["render",s]]);export{p as __pageData,m as default};
